'use client';

import { useState, useEffect, useCallback } from 'react';
import { 
  Search, 
  Plus, 
  Edit2, 
  Trash2, 
  User, 
  Mail, 
  Phone, 
  Briefcase, 
  CalendarDays,
  IndianRupee,
  X,
  ChevronLeft,
  ChevronRight,
  Filter
} from 'lucide-react';
import { useStore } from '@/store/useStore';
import { apiClient } from '@/lib/api-client';

interface Employee {
  id: string;
  employeeCode: string;
  firstName: string;
  lastName: string;
  email: string;
  phone: string | null;
  joiningDate: string;
  salary: number;
  status: 'ACTIVE' | 'INACTIVE' | 'TERMINATED' | 'ON_LEAVE';
  department: { id: string; name: string } | null;
  designation: { id: string; title: string } | null;
}

interface Department {
  id: string;
  name: string;
}

interface Designation {
  id: string;
  title: string;
}

export default function EmployeesPage() {
  const { user } = useStore();
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [departments, setDepartments] = useState<Department[]>([]);
  const [designations, setDesignations] = useState<Designation[]>([]);
  
  // Filtering & Pagination State
  const [query, setQuery] = useState('');
  const [deptId, setDeptId] = useState('');
  const [desId, setDesId] = useState('');
  const [status, setStatus] = useState('');
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [loading, setLoading] = useState(true);

  // Modal State
  const [isAddOpen, setIsAddOpen] = useState(false);
  const [isEditOpen, setIsEditOpen] = useState(false);
  const [selectedEmp, setSelectedEmp] = useState<Employee | null>(null);

  // Form State
  const [formData, setFormData] = useState({
    employeeCode: '',
    firstName: '',
    lastName: '',
    email: '',
    phone: '',
    joiningDate: new Date().toISOString().split('T')[0],
    salary: '',
    status: 'ACTIVE' as 'ACTIVE' | 'INACTIVE' | 'TERMINATED' | 'ON_LEAVE',
    departmentId: '',
    designationId: '',
  });

  const [formError, setFormError] = useState<string | null>(null);

  // Fetch lists
  const fetchEmployees = useCallback(() => {
    setLoading(true);
    apiClient.get('/api/employees', {
      query: query || undefined,
      departmentId: deptId || undefined,
      designationId: desId || undefined,
      status: status || undefined,
      page,
      limit: 10,
    })
      .then(res => {
        if (res.success) {
          setEmployees(res.employees);
          setTotalPages(res.pages);
        }
      })
      .catch(err => console.error(err))
      .finally(() => setLoading(false));
  }, [query, deptId, desId, status, page]);

  useEffect(() => {
    fetchEmployees();
  }, [fetchEmployees]);

  useEffect(() => {
    // Load dropdown items
    apiClient.get('/api/departments').then(res => res.success && setDepartments(res.data)).catch(err => console.error(err));
    apiClient.get('/api/designations').then(res => res.success && setDesignations(res.data)).catch(err => console.error(err));
  }, []);

  const handleOpenAdd = () => {
    // Generate code guess
    const nextCode = `EMP${String(employees.length + 10).padStart(3, '0')}`;
    setFormData({
      employeeCode: nextCode,
      firstName: '',
      lastName: '',
      email: '',
      phone: '',
      joiningDate: new Date().toISOString().split('T')[0],
      salary: '',
      status: 'ACTIVE',
      departmentId: departments[0]?.id || '',
      designationId: designations[0]?.id || '',
    });
    setFormError(null);
    setIsAddOpen(true);
  };

  const handleOpenEdit = (emp: Employee) => {
    setSelectedEmp(emp);
    setFormData({
      employeeCode: emp.employeeCode,
      firstName: emp.firstName,
      lastName: emp.lastName,
      email: emp.email,
      phone: emp.phone || '',
      joiningDate: new Date(emp.joiningDate).toISOString().split('T')[0],
      salary: emp.salary.toString(),
      status: emp.status,
      departmentId: emp.department?.id || '',
      designationId: emp.designation?.id || '',
    });
    setFormError(null);
    setIsEditOpen(true);
  };

  const handleSaveAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    setFormError(null);
    try {
      const res = await apiClient.post('/api/employees', formData);
      if (res.success) {
        setIsAddOpen(false);
        fetchEmployees();
      } else {
        setFormError(res.message || 'Error creating employee');
      }
    } catch (err: any) {
      setFormError(err.message || 'An error occurred');
    }
  };

  const handleSaveEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedEmp) return;
    setFormError(null);
    try {
      const res = await apiClient.put(`/api/employees/${selectedEmp.id}`, formData);
      if (res.success) {
        setIsEditOpen(false);
        fetchEmployees();
      } else {
        setFormError(res.message || 'Error updating employee');
      }
    } catch (err: any) {
      setFormError(err.message || 'An error occurred');
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this employee?')) return;
    try {
      const res = await apiClient.delete(`/api/employees/${id}`);
      if (res.success) {
        fetchEmployees();
      }
    } catch (err) {
      console.error(err);
    }
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      maximumFractionDigits: 0,
    }).format(val);
  };

  const canEdit = user?.role === 'ADMIN' || user?.role === 'HR';
  const canDelete = user?.role === 'ADMIN';

  return (
    <div className="space-y-6">
      {/* Header Panel */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h2 className="text-xl font-black text-[var(--text-primary)]">Employee Directory</h2>
          <p className="text-xs text-[var(--text-muted)] mt-0.5">Manage enterprise workforce and profile registries</p>
        </div>

        {canEdit && (
          <button
            onClick={handleOpenAdd}
            className="inline-flex items-center justify-center gap-2 rounded-xl bg-blue-600 hover:bg-blue-500 px-4 py-2.5 text-xs font-bold text-white shadow-md shadow-blue-600/10 active:scale-99 transition-all cursor-pointer"
          >
            <Plus size={16} />
            Onboard Employee
          </button>
        )}
      </div>

      {/* Filter Row */}
      <div className="glass-card p-4 grid grid-cols-1 gap-4 sm:grid-cols-2 md:grid-cols-5 items-end">
        {/* Search */}
        <div className="space-y-1.5 md:col-span-2">
          <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Search</label>
          <div className="relative">
            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-[var(--text-muted)]" />
            <input
              type="text"
              placeholder="Search code, name, email..."
              value={query}
              onChange={(e) => { setQuery(e.target.value); setPage(1); }}
              className="w-full h-10 pl-9 pr-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
            />
          </div>
        </div>

        {/* Department Filter */}
        <div className="space-y-1.5">
          <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Department</label>
          <select
            value={deptId}
            onChange={(e) => { setDeptId(e.target.value); setPage(1); }}
            className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
          >
            <option value="">All Departments</option>
            {departments.map((d) => <option key={d.id} value={d.id}>{d.name}</option>)}
          </select>
        </div>

        {/* Designation Filter */}
        <div className="space-y-1.5">
          <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Designation</label>
          <select
            value={desId}
            onChange={(e) => { setDesId(e.target.value); setPage(1); }}
            className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
          >
            <option value="">All Designations</option>
            {designations.map((d) => <option key={d.id} value={d.id}>{d.title}</option>)}
          </select>
        </div>

        {/* Status Filter */}
        <div className="space-y-1.5">
          <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Status</label>
          <select
            value={status}
            onChange={(e) => { setStatus(e.target.value); setPage(1); }}
            className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
          >
            <option value="">All Statuses</option>
            <option value="ACTIVE">Active</option>
            <option value="INACTIVE">Inactive</option>
            <option value="ON_LEAVE">On Leave</option>
            <option value="TERMINATED">Terminated</option>
          </select>
        </div>
      </div>

      {/* Employees Table */}
      <div className="glass-card overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="border-b border-[var(--card-border)] bg-slate-50/50 dark:bg-slate-900/10">
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Code</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Employee</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Department</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Designation</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Salary</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Status</th>
                {(canEdit || canDelete) && (
                  <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider text-right">Actions</th>
                )}
              </tr>
            </thead>
            <tbody className="divide-y divide-[var(--card-border)]">
              {loading ? (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-xs text-[var(--text-muted)]">
                    <div className="flex flex-col items-center justify-center gap-2">
                      <div className="h-6 w-6 animate-spin rounded-full border-2 border-blue-200 border-t-blue-600"></div>
                      <span>Loading records...</span>
                    </div>
                  </td>
                </tr>
              ) : employees.length === 0 ? (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-xs text-[var(--text-muted)] font-medium">
                    No employees found matching the filters
                  </td>
                </tr>
              ) : (
                employees.map((emp) => (
                  <tr key={emp.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-900/10 transition-colors">
                    <td className="px-6 py-4 text-xs font-bold text-[var(--text-primary)]">{emp.employeeCode}</td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-blue-50 dark:bg-blue-950 text-blue-600 text-xs font-bold uppercase shrink-0">
                          {emp.firstName[0]}{emp.lastName[0]}
                        </div>
                        <div>
                          <p className="text-xs font-bold text-[var(--text-primary)]">{emp.firstName} {emp.lastName}</p>
                          <p className="text-[10px] text-[var(--text-muted)] mt-0.5">{emp.email}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-xs text-[var(--text-secondary)] font-medium">
                      {emp.department?.name || 'Unassigned'}
                    </td>
                    <td className="px-6 py-4 text-xs text-[var(--text-secondary)] font-medium">
                      {emp.designation?.title || 'Unassigned'}
                    </td>
                    <td className="px-6 py-4 text-xs font-bold text-[var(--text-primary)]">
                      {formatCurrency(emp.salary)}
                    </td>
                    <td className="px-6 py-4">
                      <span 
                        className={`inline-flex items-center rounded-full px-2 py-0.5 text-[10px] font-semibold border
                          ${emp.status === 'ACTIVE' 
                            ? 'bg-emerald-50 dark:bg-emerald-950/20 text-emerald-600 dark:text-emerald-400 border-emerald-100 dark:border-emerald-900/10' 
                            : emp.status === 'ON_LEAVE'
                            ? 'bg-amber-50 dark:bg-amber-950/20 text-amber-600 dark:text-amber-400 border-amber-100 dark:border-amber-900/10'
                            : 'bg-slate-100 dark:bg-slate-900 text-slate-500 dark:text-slate-400 border-slate-200 dark:border-slate-800'
                          }
                        `}
                      >
                        {emp.status.replace('_', ' ')}
                      </span>
                    </td>
                    {(canEdit || canDelete) && (
                      <td className="px-6 py-4 text-right">
                        <div className="flex justify-end gap-2">
                          {canEdit && (
                            <button
                              onClick={() => handleOpenEdit(emp)}
                              className="p-1.5 rounded-lg border border-[var(--card-border)] hover:bg-[var(--primary-light)] text-[var(--text-secondary)] hover:text-blue-600 transition-colors"
                              title="Edit Employee"
                            >
                              <Edit2 size={13} />
                            </button>
                          )}
                          {canDelete && (
                            <button
                              onClick={() => handleDelete(emp.id)}
                              className="p-1.5 rounded-lg border border-[var(--card-border)] hover:bg-red-50 dark:hover:bg-red-950/15 text-[var(--text-secondary)] hover:text-red-600 transition-colors"
                              title="Delete Employee"
                            >
                              <Trash2 size={13} />
                            </button>
                          )}
                        </div>
                      </td>
                    )}
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>

        {/* Pagination bar */}
        {totalPages > 1 && (
          <div className="flex items-center justify-between px-6 py-4 border-t border-[var(--card-border)] bg-slate-50/20 dark:bg-slate-900/5">
            <span className="text-[10px] font-semibold text-[var(--text-muted)]">
              Page {page} of {totalPages}
            </span>
            <div className="flex gap-2">
              <button
                onClick={() => setPage(p => Math.max(1, p - 1))}
                disabled={page === 1}
                className="p-1.5 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] hover:bg-[var(--primary-light)] text-[var(--text-secondary)] disabled:opacity-40 transition-all cursor-pointer"
              >
                <ChevronLeft size={14} />
              </button>
              <button
                onClick={() => setPage(p => Math.min(totalPages, p + 1))}
                disabled={page === totalPages}
                className="p-1.5 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] hover:bg-[var(--primary-light)] text-[var(--text-secondary)] disabled:opacity-40 transition-all cursor-pointer"
              >
                <ChevronRight size={14} />
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Add / Edit Form Modal Dialog */}
      {(isAddOpen || isEditOpen) && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="w-full max-w-lg rounded-2xl border border-[var(--card-border)] bg-[var(--card-bg)] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="flex items-center justify-between px-6 py-4 border-b border-[var(--card-border)] bg-slate-50/50 dark:bg-slate-900/10">
              <h3 className="font-bold text-sm text-[var(--text-primary)]">
                {isAddOpen ? 'Onboard New Employee' : 'Edit Employee Registry'}
              </h3>
              <button 
                onClick={() => { setIsAddOpen(false); setIsEditOpen(false); }}
                className="text-[var(--text-muted)] hover:text-[var(--text-primary)] transition-colors cursor-pointer"
              >
                <X size={16} />
              </button>
            </div>
            
            <form onSubmit={isAddOpen ? handleSaveAdd : handleSaveEdit} className="p-6 space-y-4">
              {formError && (
                <div className="p-3 text-xs font-semibold rounded-xl bg-red-50 dark:bg-red-950/20 text-red-600 dark:text-red-400 border border-red-200/50">
                  {formError}
                </div>
              )}

              {/* Form Grid */}
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                {/* Employee Code */}
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Employee Code</label>
                  <input
                    type="text"
                    required
                    value={formData.employeeCode}
                    onChange={(e) => setFormData({ ...formData, employeeCode: e.target.value })}
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  />
                </div>

                {/* Salary */}
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Base Salary (INR)</label>
                  <input
                    type="number"
                    required
                    placeholder="e.g. 75000"
                    value={formData.salary}
                    onChange={(e) => setFormData({ ...formData, salary: e.target.value })}
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  />
                </div>

                {/* First Name */}
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">First Name</label>
                  <input
                    type="text"
                    required
                    value={formData.firstName}
                    onChange={(e) => setFormData({ ...formData, firstName: e.target.value })}
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  />
                </div>

                {/* Last Name */}
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Last Name</label>
                  <input
                    type="text"
                    required
                    value={formData.lastName}
                    onChange={(e) => setFormData({ ...formData, lastName: e.target.value })}
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  />
                </div>

                {/* Email */}
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Email Address</label>
                  <input
                    type="email"
                    required
                    value={formData.email}
                    onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  />
                </div>

                {/* Phone */}
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Phone Number</label>
                  <input
                    type="text"
                    value={formData.phone}
                    onChange={(e) => setFormData({ ...formData, phone: e.target.value })}
                    placeholder="+91..."
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  />
                </div>

                {/* Department */}
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Department</label>
                  <select
                    value={formData.departmentId}
                    onChange={(e) => setFormData({ ...formData, departmentId: e.target.value })}
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  >
                    {departments.map((d) => <option key={d.id} value={d.id}>{d.name}</option>)}
                  </select>
                </div>

                {/* Designation */}
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Designation</label>
                  <select
                    value={formData.designationId}
                    onChange={(e) => setFormData({ ...formData, designationId: e.target.value })}
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  >
                    {designations.map((d) => <option key={d.id} value={d.id}>{d.title}</option>)}
                  </select>
                </div>

                {/* Joining Date */}
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Joining Date</label>
                  <input
                    type="date"
                    required
                    value={formData.joiningDate}
                    onChange={(e) => setFormData({ ...formData, joiningDate: e.target.value })}
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  />
                </div>

                {/* Status */}
                <div className="space-y-1">
                  <label className="text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Status</label>
                  <select
                    value={formData.status}
                    onChange={(e) => setFormData({ ...formData, status: e.target.value as any })}
                    className="w-full h-10 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
                  >
                    <option value="ACTIVE">Active</option>
                    <option value="INACTIVE">Inactive</option>
                    <option value="ON_LEAVE">On Leave</option>
                    <option value="TERMINATED">Terminated</option>
                  </select>
                </div>
              </div>

              {/* Modal Action footer */}
              <div className="flex justify-end gap-3 pt-4 border-t border-[var(--card-border)]">
                <button
                  type="button"
                  onClick={() => { setIsAddOpen(false); setIsEditOpen(false); }}
                  className="px-4 py-2 rounded-xl border border-[var(--card-border)] hover:bg-slate-50 dark:hover:bg-slate-900/40 text-xs font-semibold text-[var(--text-secondary)] transition-colors cursor-pointer"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="px-4 py-2 rounded-xl bg-blue-600 hover:bg-blue-500 text-xs font-bold text-white shadow-md shadow-blue-600/10 transition-colors cursor-pointer"
                >
                  {isAddOpen ? 'Save Employee' : 'Update Employee'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
